bad_example:
key owner;
default {
    state_entry() { owner = llGetOwner(); }
    // CHANGED_OWNER never handled — owner is stale after transfer
}

good_example:
key owner;
default {
    state_entry() { owner = llGetOwner(); }
    changed(integer change) {
        if (change & CHANGED_OWNER) llResetScript();
    }
}

